prompt.output_format:
Respond ONLY with this JSON structure:
{
  "mode": "SMALL_TALK | DOCUMENT_SEARCH | ANALYTICAL_SEARCH | TECHNICAL_ISSUE",
  "reasoning": "brief explanation...",
  "routes": {
    "use_vector": boolean,
    "use_graph": boolean,
    "use_hive_mind": boolean
  },
  "entities_to_extract": ["list", "of", "entities"]
}

example.output:
{
  "mode": "ANALYTICAL_SEARCH", 
  "reasoning": "Requires connecting a person to a project",
  "routes": {"use_vector": true, "use_graph": true, "use_hive_mind": false},
  "entities_to_extract": ["Lukas Hoffmann", "B2Run"]
}

{
  "mode": "TECHNICAL_ISSUE", 
  "reasoning": "Debugging a technical error",
  "routes": {"use_vector": true, "use_graph": false, "use_hive_mind": true},
  "entities_to_extract": ["503 error", "websocket"]
}

{
  "mode": "ANALYTICAL_SEARCH", 
  "reasoning": "Query asks about a specific person (Kimberley) - must use Graph to find entity relationships",
  "routes": {"use_vector": true, "use_graph": true, "use_keyword": true, "use_hive_mind": false},
  "entities_to_extract": ["Kimberley", "Branche"]
}
